arguments.command:
python3 << 'EOF'
import bisect

symbols = []
with open('/tmp/mono_all_funcs.txt') as f:
    for line in f:
        parts = line.strip().split()
        if len(parts) >= 3:
            addr = int(parts[0], 16)
            try:
                size = int(parts[1])
            except ValueError:
                size = int(parts[1], 16) if parts[1].startswith('0x') else 0
            name = parts[2]
            if size > 0:
                symbols.append((addr, size, name))

symbols.sort()
addrs_only = [s[0] for s in symbols]

targets = [0x2f4b20, 0x2f4c84]
for pc in targets:
    idx = bisect.bisect_right(addrs_only, pc) - 1
    if idx >= 0:
        sym_addr, sym_size, sym_name = symbols[idx]
        offset = pc - sym_addr
        if offset < sym_size:
            print(f"  {pc:#010x} -> {sym_name}+{offset:#x}")
        else:
            print(f"  {pc:#010x} -> NOT in FUNC (nearest: {sym_name} @ {sym_addr:#x}, size {sym_size}, ends {sym_addr+sym_size:#x})")
    else:
        print(f"  {pc:#010x} -> no symbol found")
EOF

